function getVideoSize(media) {
  return Number(media.document.size)
}

function isVideo(media) {
    return media.video && 1;
}

function isHandleVideo(medias){
    return medias.some(media => media["Type"] == 'FileType.VIDEO')
}

async function connectWithTimeout(client, timeout = 20000) {
    const timeoutPromise = new Promise((resolve) =>
        setTimeout(() => resolve(false), timeout)
    );

    try {
        const connectResult = await Promise.race([
            client.connect().then(() => true),
            timeoutPromise,
        ]);
        return connectResult;
    } catch {
        return false;
    }
}

const username = medias[0]["Username"];
const msgIds = medias.map(x => Number(x["MessageId"]))

async function handleMedia() {
  const f_result = []
  const client = new TelegramClient(
        new StringSession(stringSession),
        apiId,
        apiHash,
        { connectionRetries: 5 }
      );
  try {
    await client.connect();
    const result = await client.invoke(
      new Api.channels.GetMessages({
        channel: username,
        id: msgIds
      })
    );
    const teleMsgs = result.messages;
    for(let i = 0; i < medias.length; i++) {
      const media = medias[i];
      const teleMsg = teleMsgs.find(x => x["id"].toString() == media["MessageId"].toString())
      if(!teleMsg) {
          continue;
      }
      const id = media["Id"];
      const syncTime = media["MediaSyncTime"];
      const isMediaVideo = isVideo(teleMsg.media);
      if (isMediaVideo) {
          const videoSize = getVideoSize(teleMsg.media);
          if (videoSize > maxSizeBytes){
            f_result.push({
                json : {
                      id,
                      size: videoSize,
                      isLarge: true
                  }
            });
            continue;
          }
      }
      let buffer = await client.downloadMedia(teleMsg, {
        worker: 1
      });
      const mimeType = await fileType.fromBuffer(buffer);
      const size = buffer.length;
      const isLarge = size > maxSizeBytes;
      if (isLarge){
        f_result.push({
            json : {
                  id,
                  size,
                  isLarge,
                  action: 'IGNORE',
                  credential: media["Credentials"],
              }
        });
      }
      else {
        f_result.push({
          json : {
            id,
            isLarge: false,
            syncTime,
            mimeType,
            action: 'UPLOAD',
            credential: media["Credentials"],
            folderToken: 'MwlqfQO8VlRvuzdhGr7lIlgSgah', //media["Folder_token"],
            size,
            fileName: `${media["Id"]}_${media["ChatId"]}_${media["MessageId"]}.${mimeType?.ext}`
          },
          binary: {
              data: {
                data: buffer,
                mimeType: mimeType?.mime,
                fileName: `${media["Id"]}_${media["ChatId"]}_${media["MessageId"]}.${mimeType?.ext}`
              }
          }
        })
      }
      buffer = null;
    }
  } finally {
    await client.disconnect();
  }
  return f_result;
};

